import{_ as e,o as t,c as r,a2 as l}from"./chunks/framework.Cr-Z7ngm.js";const p=JSON.parse('{"title":"收不到短信验证码","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"troubleshooting/sms-code.md","filePath":"zh-CN/troubleshooting/sms-code.md"}'),o={name:"troubleshooting/sms-code.md"};function i(h,a,s,n,d,c){return t(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="收不到短信验证码" tabindex="-1">收不到短信验证码 <a class="header-anchor" href="#收不到短信验证码" aria-label="Permalink to &quot;收不到短信验证码&quot;">​</a></h1><p>当无法收到短信验证码时，请按以下 7 步顺序排查，绝大多数情况可以解决。</p><h2 id="自助排查步骤" tabindex="-1">自助排查步骤 <a class="header-anchor" href="#自助排查步骤" aria-label="Permalink to &quot;自助排查步骤&quot;">​</a></h2><h3 id="步骤-1-刷新手机网络信号" tabindex="-1">步骤 1：刷新手机网络信号 <a class="header-anchor" href="#步骤-1-刷新手机网络信号" aria-label="Permalink to &quot;步骤 1：刷新手机网络信号&quot;">​</a></h3><p>短暂开启手机的飞行模式，等待约 10 秒后关闭，重新连接网络后重试获取验证码。</p><h3 id="步骤-2-检查短信拦截设置" tabindex="-1">步骤 2：检查短信拦截设置 <a class="header-anchor" href="#步骤-2-检查短信拦截设置" aria-label="Permalink to &quot;步骤 2：检查短信拦截设置&quot;">​</a></h3><p>部分安全管理类 App 或手机系统会误拦截验证码短信，请检查：</p><ul><li>手机内置的骚扰拦截或垃圾信息文件夹</li><li>第三方安全软件（如手机管家、360 卫士等）的短信拦截记录</li></ul><h3 id="步骤-3-检查手机存储与-sim-卡状态" tabindex="-1">步骤 3：检查手机存储与 SIM 卡状态 <a class="header-anchor" href="#步骤-3-检查手机存储与-sim-卡状态" aria-label="Permalink to &quot;步骤 3：检查手机存储与 SIM 卡状态&quot;">​</a></h3><ul><li>短信存储已满：清理收件箱中不必要的短信</li><li>SIM 卡故障：尝试将手机卡插入另一部手机接收，判断是否为卡槽问题</li><li>SIM 卡氧化：取出手机卡，用清洁软布擦拭芯片后重新插入</li></ul><h3 id="步骤-4-确认手机话费与停机状态" tabindex="-1">步骤 4：确认手机话费与停机状态 <a class="header-anchor" href="#步骤-4-确认手机话费与停机状态" aria-label="Permalink to &quot;步骤 4：确认手机话费与停机状态&quot;">​</a></h3><p>因欠费停机后，缴费复机 24 小时内可能仍无法正常接收商业短信。确认账户余额充足，如为复机第一天可次日重试。</p><h3 id="步骤-5-确认所在地网络与运营商状态" tabindex="-1">步骤 5：确认所在地网络与运营商状态 <a class="header-anchor" href="#步骤-5-确认所在地网络与运营商状态" aria-label="Permalink to &quot;步骤 5：确认所在地网络与运营商状态&quot;">​</a></h3><p>所在地区运营商可能出现临时故障。稍等片刻后重试，或询问使用相同运营商的朋友是否有类似问题。</p><h3 id="步骤-6-检查手机短信接收功能" tabindex="-1">步骤 6：检查手机短信接收功能 <a class="header-anchor" href="#步骤-6-检查手机短信接收功能" aria-label="Permalink to &quot;步骤 6：检查手机短信接收功能&quot;">​</a></h3><p>确认手机没有关闭短信接收功能。查看设置 - 消息设置 - 通知开关是否已开启。</p><h3 id="步骤-7-重启设备与卡片" tabindex="-1">步骤 7：重启设备与卡片 <a class="header-anchor" href="#步骤-7-重启设备与卡片" aria-label="Permalink to &quot;步骤 7：重启设备与卡片&quot;">​</a></h3><ul><li>重启手机：彻底关机，等待一分钟后重新开机</li><li>重新插拔 SIM 卡：关机后取出 SIM 卡，重新安装牢固后开机</li></ul><h2 id="备用方案" tabindex="-1">备用方案 <a class="header-anchor" href="#备用方案" aria-label="Permalink to &quot;备用方案&quot;">​</a></h2><p>如自助排查后仍无法解决：</p><p>客服热线：4000712688<br> 在线客服：在 App 或网站内点击「在线客服」</p><p>如需紧急处理，直接拨打电话是最高效的方式。</p><p>大多数情况下，按照「刷新网络 → 检查拦截 → 重启设备」的顺序操作即可解决问题。</p>',23)])])}const b=e(o,[["render",i]]);export{p as __pageData,b as default};
